import clsx from 'clsx';
import { type MutableRefObject, type ReactElement } from 'react';

import Colors from '@dynatrace/strato-design-tokens/colors';
import { ViewIcon, ViewOffIcon } from '@dynatrace/strato-icons';

import {
  coloredEyeOffIcon,
  eyeIcon,
  singleDimensionIcon,
} from './ChartLegendIcon.sty.js';
import { getTokenComputedStyle } from '../../../../../utils/getTokenComputedStyle.js';
import { getValidColor } from '../../../../../utils/getValidColor.js';
import { useLegend } from '../../hooks/useLegend.js';
import {
  baseLegendButton,
  legendItemButton,
} from '../ChartLegendItem/ChartLegendItem.sty.js';

interface LegendIconProps {
  visible: boolean;
  hover: boolean;
  disabled: boolean;
  color: string;
  icon?: ReactElement;
  buttonRef: MutableRefObject<HTMLButtonElement | null>;
  onMouseEnter: () => void;
  onButtonClick?: () => void;
}

export const ChartLegendIcon = (props: LegendIconProps) => {
  const {
    visible,
    hover,
    disabled,
    color,
    icon,
    buttonRef,
    onMouseEnter,
    onButtonClick,
  } = props;

  const { interactionsDisabled } = useLegend();

  const validColor = getTokenComputedStyle(getValidColor(color));

  const withCustomIconOrDefault = icon ? (
    icon
  ) : (
    <span
      data-testid="chart-legend-item-icon-visible"
      className={singleDimensionIcon}
      style={{ backgroundColor: validColor }}
    />
  );

  const iconVisibleOrHidden = visible ? (
    withCustomIconOrDefault
  ) : (
    <ViewOffIcon
      data-testid="chart-legend-item-icon-hidden"
      size="small"
      className={coloredEyeOffIcon}
      style={{ color }}
    />
  );

  return (
    <button
      ref={buttonRef}
      aria-label="Hide"
      data-testid="chart-legend-item-icon"
      data-dt-children-name="LegendHideItem"
      data-dt-properties={visible ? 'state:hide' : 'state:show'}
      disabled={disabled}
      onFocus={(e) => {
        onMouseEnter();
      }}
      onClick={onButtonClick}
      onMouseEnter={onMouseEnter}
      className={clsx(
        baseLegendButton,
        legendItemButton({
          isInteractive: !interactionsDisabled,
        }),
      )}
      style={{
        color: visible || hover ? color : Colors.Text.Neutral.Subdued,
      }}
    >
      {hover && visible && !disabled ? (
        <ViewIcon
          data-testid="chart-legend-item-icon-hover"
          size="small"
          className={eyeIcon}
        />
      ) : (
        iconVisibleOrHidden
      )}
    </button>
  );
};
